/**
  * Buttons to Show/Hide Tiddlers:
  * Examples:
  *  - Show all tiddlers
  *    <<button Click Me!;ui.open.all>>
  */
tw.macros.button = (title, msg, payload = '', id = '') => {
  return tw.ui.button(title, msg, payload, id);
};

/**
 * ## Description
 * Obsidian-style command palette. Ctrl/Cmd+K opens an overlay to run actions
 * and quick-open notes by name:
 *   - empty input or a `>`-prefixed query → the action list (filtered);
 *   - any other text → ranked note search (reusing `tw.core.search.search`).
 * Arrow keys move, Enter runs, Escape closes.
 *
 * The `<dialog>` is built in JS (so it can't collide with layout ids). The
 * document-level keydown is bound once (guarded via `tw.tmp`) and is ignored
 * while the edit dialog is open, so editing keeps its own keyboard.
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
(function() {

  const ACTIONS = [
    {label: 'New note', event: 'tiddler.new'},
    {label: 'Save all', event: 'save.all'},
    {label: 'Open all notes', event: 'ui.open.all', payload: {tag: '', title: ''}},
    {label: 'Close all notes', event: 'ui.close.all', payload: {tag: '*', title: '*'}},
    {label: 'Show favorites', event: 'ui.open.all', payload: {tag: 'Favorite', title: '*'}},
    {label: 'Reload UI', event: 'ui.reload'},
    {label: 'Open Settings', event: 'tiddler.show', payload: '$Settings'},
    {label: 'Toggle sidebar', run: () => document.getElementById('sidebar')?.classList.toggle('open')},
  ];

  let dialog;
  let input;
  let results;
  let items = [];
  let selected = 0;

  tw.tmp = tw.tmp || {};

  wireUp('ui.loaded', init);
  wireUp('ui.reloaded', init);

  function init() {
    document.getElementById('command-palette')?.remove();
    dialog = document.createElement('dialog');
    dialog.id = 'command-palette';
    dialog.innerHTML =
      '<input id="palette-input" type="text" autocomplete="off" spellcheck="false" ' +
      'placeholder="Search commands and notes…  (&gt; for commands only)" />' +
      '<div id="palette-results"></div>';
    document.body.appendChild(dialog);
    input = dialog.querySelector('#palette-input');
    results = dialog.querySelector('#palette-results');

    input.addEventListener('input', () => {selected = 0; render();});
    input.addEventListener('keydown', onInputKeydown);
    results.addEventListener('click', onResultsClick);
    dialog.addEventListener('close', () => {input.value = '';});

    if (!tw.tmp.commandPaletteBound) {
      tw.tmp.commandPaletteBound = true;
      document.addEventListener('keydown', onDocKeydown);
    }
  }

  function onDocKeydown(e) {
    if (e.key !== 'k' || !(e.ctrlKey || e.metaKey)) return;
    if (document.getElementById('new-dialog')?.open) return; // editing owns the keyboard
    e.preventDefault();
    open();
  }

  function open() {
    if (!dialog) return;
    input.value = '';
    selected = 0;
    render();
    if (!dialog.open) dialog.showModal();
    input.focus();
  }

  function buildItems() {
    let q = input.value;
    // `>` forces commands-only (Obsidian convention).
    if (q[0] === '>') return actionItems(q.slice(1).trim().toLowerCase());
    // Empty input → the full command list.
    if (!q.trim()) return actionItems('');
    // Plain text → matching commands first, then matching notes.
    return [...actionItems(q.trim().toLowerCase()), ...noteItems(q)];
  }

  function actionItems(needle) {
    return ACTIONS
      .filter(a => !needle || a.label.toLowerCase().includes(needle))
      .map(a => ({label: a.label, hint: 'command', run: () => runAction(a)}));
  }

  function noteItems(q) {
    return tw.core.search.search(q, tw.tiddlers.all, {all: false})
      .filter(t => t && t.type) // drop the "No results!" placeholder (no type)
      .slice(0, 50)
      .map(t => ({label: t.title, hint: t.type, run: () => openNote(t.title)}));
  }

  function render() {
    items = buildItems();
    if (selected >= items.length) selected = Math.max(0, items.length - 1);
    if (!items.length) {
      results.innerHTML = '<div class="palette-empty">No matches</div>';
      return;
    }
    results.innerHTML = items.map((it, i) =>
      `<div class="palette-row${i === selected ? ' selected' : ''}" data-index="${i}">` +
      `<span class="palette-label">${esc(it.label)}</span>` +
      `<span class="palette-hint">${esc(it.hint || '')}</span></div>`,
    ).join('');
  }

  function onInputKeydown(e) {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      selected = Math.min(selected + 1, items.length - 1);
      render();
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      selected = Math.max(selected - 1, 0);
      render();
    } else if (e.key === 'Enter') {
      e.preventDefault();
      runSelected();
    }
    // Escape is handled natively by <dialog>
  }

  function onResultsClick(e) {
    let row = e.target.closest('.palette-row');
    if (!row) return;
    selected = Number(row.getAttribute('data-index'));
    runSelected();
  }

  function runSelected() {
    let it = items[selected];
    if (!it) return;
    dialog.close();
    it.run();
  }

  function runAction(a) {
    if (a.run) return a.run();
    tw.events.send(a.event, a.payload);
  }

  function openNote(title) {
    tw.events.send('tiddler.show', title);
    if (tw.tabs) tw.tabs.activate(title);
  }

  function esc(s) {
    return tw.core.common.escapeHtml(String(s));
  }

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'CommandPalette');
  }

})();

/**
 * ## Description
 * Provides all theme logic
 * Provides <<ThemeSelector>> widget
 *   listing all tiddlers tagged with $Theme
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.1
 * }
 * ```
 */
(function(){

  wireUp('ui.loaded', () => {
    tw.theme = {
      stylesheets: {
        custom: new CSSStyleSheet(),
      },
      getThemeNames,
    };
    document.adoptedStyleSheets.push(tw.theme.stylesheets.custom);
    themeUpdate();
  });

  wireUp('tiddler.updated', tiddlerChanged);
  wireUp('tiddler.deleted', tiddlerChanged);
  function tiddlerChanged(title) {
    if (tiddlerIsThemeRelevant(title))
      return themeUpdate();
    if (tiddlerIsATheme(title))
      return themesUpdate();
  }

  wireUp('theme.switch', themeSwitch);
  function themeSwitch(theme) {
    if (!theme) return;
    if (!tw.call('tiddlerExists', theme)) return tw.ui.notify(`Unknown theme tiddler '${theme}'!`, 'E');
    let tiddler = tw.run.getTiddler('$Theme');
    tiddler.text = `[[${theme}]]`;
    delete tiddler.doNotSave;
    tw.run.updateTiddlerHard('$Theme', tiddler);
    if (theme.match(/Dark/)) {
      tw.core.dom.enableStyleSheet('highlight-dark');
      tw.core.dom.disableStyleSheet('highlight-light');
    } else {
      tw.core.dom.enableStyleSheet('highlight-light');
      tw.core.dom.disableStyleSheet('highlight-dark');
    }
    tw.events.send('tiddler.refresh', '$Theme');
    themeUpdate(theme);
    tw.events.send('save.silent');
  }

  wireUp('ui.reloaded', themeUpdate);
  function themeUpdate() {
    let css = getThemeStyleSheets().map(tw.run.getTiddlerTextRaw).join('\n');
    tw.theme.stylesheets.custom.replaceSync(css);
  }

  function tiddlerIsATheme(title) {
    return tw.run.getTiddler(title)?.tags.includes('$Theme');
  }

  function themesUpdate() {
    tw.events.send('tiddler.refresh', '$Themes');
  }

  function tiddlerIsThemeRelevant(title) {
    let themeName = getCurrentThemeName();
    return title === '$Theme' || title === themeName || getThemeStyleSheets().includes(title);
  }
  function getCurrentThemeName() {
    return tw.run.getTiddlerTextRaw('$Theme').replace(/[\[\]]/g, ''); // Remove possible [[links]]
  }
  function getThemeNames() {
    return tw.run.getTiddlersByTag('$Theme').map(t => t.title);
  }
  function getThemeStyleSheets() {
    let theme = getCurrentThemeName();
    if (!tw.call('tiddlerExists', theme)) {
      tw.ui.notify('Unable to determine theme name from $Theme tiddler! Falling back on $CoreTheme', 'W');
      theme = '$CoreTheme';
    }
    return tw.run.getTiddlerList(theme);
  }

  tw.macros.core.ThemeSelector = () => {
    let theme = getCurrentThemeName();
    return `<select id="theme-select" onchange="tw.events.send('theme.switch', this.value);">
    ${getThemeNames().sort().map(n => `<option value="${n}"${n === theme ? ' selected' : ''}>${n.replace(/(^\$)|(Theme)/g, '')}</option>`).join('\n')}
  </select>`;
  };

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'CoreThemeManager');
  }
})();

/**
 * ## Description
 * Fills the left sidebar with an Obsidian-style explorer: a list of notes
 * (non-system tiddlers, sorted) and a list of tags. Rows are clickable —
 * notes open + activate their tab; tags open all matching notes.
 *
 * Renders into `#explorer-notes` / `#explorer-tags` (provided by the layout)
 * and rebuilds live on note create/update/delete and on story changes (to keep
 * the "open" highlight current). Reuses `tw.macros.core.allTags()` and
 * `tw.util.titleMatch`.
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
(function() {

  let notesEl;
  let tagsEl;

  wireUp('ui.loaded', init);
  wireUp('ui.reloaded', init);

  // Keep the note list current as the store changes.
  ['tiddler.created', 'tiddler.updated', 'tiddler.deleted', 'tiddler.removed', 'tiddler.modified']
    .forEach(ev => wireUp(ev, render));
  // Keep the "open" highlight current as tabs open/close.
  ['story.rendered', 'story.changed'].forEach(ev => wireUp(ev, render));

  function init() {
    notesEl = document.getElementById('explorer-notes');
    tagsEl = document.getElementById('explorer-tags');
    if (notesEl && !notesEl._explorerBound) {
      notesEl._explorerBound = true;
      notesEl.addEventListener('click', onNoteClick);
    }
    if (tagsEl && !tagsEl._explorerBound) {
      tagsEl._explorerBound = true;
      tagsEl.addEventListener('click', onTagClick);
    }
    render();
  }

  function render() {
    if (notesEl) notesEl.innerHTML = notesHtml();
    if (tagsEl) tagsEl.innerHTML = tagsHtml();
  }

  function notesHtml() {
    let open = new Set(tw.tiddlers.visible);
    let titles = tw.tiddlers.all
      .filter(tw.util.titleMatch('!^\\$'))
      .map(t => t.title)
      .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
    let rows = titles.map(title =>
      `<a class="explorer-note${open.has(title) ? ' open' : ''}" data-note="${attr(title)}" title="${attr(title)}">${esc(title)}</a>`,
    ).join('');
    return `<div class="explorer-section-title">Notes</div>${rows || '<div class="explorer-empty">No notes yet</div>'}`;
  }

  function tagsHtml() {
    let tags = tw.macros.core.allTags()
      .filter(t => !/^\$/.test(t)) // hide system tags
      .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
    if (!tags.length) return '';
    let pills = tags.map(t =>
      `<a class="explorer-tag" data-tag="${attr(t)}">${esc(t)}</a>`,
    ).join('');
    return `<div class="explorer-section-title">Tags</div><div class="explorer-tags-list">${pills}</div>`;
  }

  function onNoteClick(e) {
    let row = e.target.closest('[data-note]');
    if (!row) return;
    let title = row.getAttribute('data-note');
    tw.events.send('tiddler.show', title);
    if (tw.tabs) tw.tabs.activate(title);
    closeDrawer();
  }

  function onTagClick(e) {
    let row = e.target.closest('[data-tag]');
    if (!row) return;
    tw.events.send('ui.open.all', {tag: row.getAttribute('data-tag'), title: '*'});
    closeDrawer();
  }

  function closeDrawer() {
    document.getElementById('sidebar')?.classList.remove('open');
  }

  function attr(s) {
    return String(s).replace(/&/g, '&amp;').replace(/"/g, '&quot;');
  }

  function esc(s) {
    return tw.core.common.escapeHtml(String(s));
  }

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'ExplorerPlugin');
  }

})();

// Send any message <<command ui.open.all pck:website>>
tw.macros.core.command = (msg, payload = '') => {
  return tw.ui.button(`Send: ${msg}:${payload}`, msg, payload, '', 'title="Send Command"');
};
// Reload UI
tw.macros.core.Reload = () => {
  return tw.ui.button('🔄️', 'ui.reload', null, '', 'title="Reload"');
};
tw.macros.core.Save = () => {
  return tw.ui.button('{{$IconSave}}', 'save.all', null, '', 'title="Save"');
};
tw.macros.core.Settings = (size = '22') => {
  return tw.ui.button(`{{$IconSettings|size:${size}px}}`, 'tiddler.show', '$Settings', '', 'title="Settings"');
};
tw.macros.core.Tag = (size = '22') => {
  return tw.ui.button(`{{$IconTag|${size}}}`, 'tiddler.show', 'Tags', '', 'title="Settings"');
};
tw.macros.core.New = () => {
  return tw.ui.button('{{$IconNew}}', 'tiddler.new', null);
};
tw.macros.core.TagInput = ({id}) => {
  const tags = tw.macros.core.allTags();
  return `<input id="${id}" placeholder="Tags" list="${id}-tags"/><datalist id="${id}-tags">${tags.map(t => `<option value="${t}">${t}</option>`).join('\n')}</datalist>`;
};
// Lists types used in all tiddlers
tw.macros.core.AllTypesMacro = () => {
  return tw.lib.markdown([...new Set(tw.tiddlers.all.map(t => `* [${t.type}](#msg:tiddlers.show:type:${t.type})\n`))].join(''));
};

/**
 * ## Description
 * Backup your data to a private [GitHub Gist](https://gist.github.com).
 * Each tiddler is stored as a separate file so changes appear as diffs in
 * the gist's history. A sidecar `_twikki.meta.json` holds the visible/trashed
 * lists. On first save (when no gistId is configured) a new private gist is
 * created and its id is written back to `$GeneralSettings`.
 *
 * Loading this plugin overrides any previously installed backup provider
 *
 * Required `$GeneralSettings` shape:
 * ```json
 * {
 *   "backup": {
 *     "Gist": {
 *       "accessToken": "ghp_xxx",
 *       "gistId": "",
 *       "description": "TWikki backup"
 *     }
 *   }
 * }
 * ```
 * The PAT must have the `gist` scope. GitHub enforces a 10 MB per-file
 * limit; oversized tiddlers will be rejected by the API.
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
(function() {

  const META_FILENAME = '_twikki.meta.json';
  const FORMAT = 'twikki-gist-v1';
  const DEFAULT_DESCRIPTION = 'TWikki backup';

  // Tiddlers tagged $NoBackup are never pushed and are preserved across restore.
  const isNoBackup = t => t.tags?.includes('$NoBackup');

  tw.macros.backup = {
    restoreButton() {
      return tw.ui.button('{{$IconRestore}}', 'backup.restore', null, 'restore', 'title="Restore Backup Data"');
    },
    backupButton() {
      return tw.ui.button('{{$IconBackup}}', 'backup.save', null, 'backup', 'title="Backup Data"');
    },
    async restore() {
      let cfg = readConfig();
      if (!cfg) return;
      if (!cfg.gistId) return tw.ui.notify('No Gist gistId found in $GeneralSettings.backup.Gist!', 'W');
      let res = await fetch('https://api.github.com/gists/' + cfg.gistId, {headers: authHeaders(cfg.accessToken)});
      if (!res.ok) {
        console.error('GistBackup restore', await readError(res));
        return tw.ui.notify(`Restore failed '${res.status}' (see log)`, 'E');
      }
      let gist = await res.json();
      let rebuilt = rebuildTiddlersFromGist(gist);

      // Preserve local $NoBackup tiddlers across restore — they were never pushed,
      // so the gist has no authoritative copy. Local wins on title collision.
      const localKeep = tw.tiddlers.all.filter(isNoBackup);
      const localKeepTrashed = tw.tiddlers.trashed.filter(isNoBackup);
      const rebuiltTitles = new Set(rebuilt.all.map(t => t.title));
      const rebuiltTrashedTitles = new Set(rebuilt.trashed.map(t => t.title));
      rebuilt.all.push(...localKeep.filter(t => !rebuiltTitles.has(t.title)));
      rebuilt.trashed.push(...localKeepTrashed.filter(t => !rebuiltTrashedTitles.has(t.title)));

      Object.assign(tw.tiddlers, rebuilt);
      tw.run.save();
      if (confirm('Restore complete. Would you like to reload?')) tw.events.send('reboot.hard');
      tw.ui.notify(`Restore complete! (${rebuilt.all.length} tiddlers, ${localKeep.length} kept local)`, 'S');
    },
    async save() {
      let cfg = readConfig();
      if (!cfg) return;
      let files = {};
      tw.tiddlers.all
        .filter(t => !isNoBackup(t))
        .forEach(t => {
          files[tiddlerFilename(t.title)] = {content: JSON.stringify(t, null, 2)};
        });
      files[META_FILENAME] = {content: JSON.stringify({
        format: FORMAT,
        visible: tw.tiddlers.visible,
        trashed: tw.tiddlers.trashed.filter(t => !isNoBackup(t)),
      }, null, 2)};
      let body, res;
      if (cfg.gistId) {
        let remote = await fetchRemoteFiles(cfg);
        if (!remote) return;
        Object.keys(remote).forEach(name => {
          if (!files[name]) files[name] = null; // Delete files no longer present locally
        });
        body = JSON.stringify({files, description: cfg.description});
        res = await fetch('https://api.github.com/gists/' + cfg.gistId, {
          method: 'PATCH',
          headers: mutationHeaders(cfg.accessToken),
          body,
        });
      } else {
        body = JSON.stringify({public: false, description: cfg.description, files});
        res = await fetch('https://api.github.com/gists', {
          method: 'POST',
          headers: mutationHeaders(cfg.accessToken),
          body,
        });
      }
      if (!res.ok) {
        console.error('GistBackup save', await readError(res));
        return tw.ui.notify(`Backup failed '${res.status}' (see log)`, 'E');
      }
      if (!cfg.gistId) {
        let created = await res.json();
        persistGistId(created.id);
        tw.ui.notify(`New gist created (${created.id}) and saved to $GeneralSettings`, 'I');
      }
      let fileCount = Object.values(files).filter(f => f !== null).length;
      tw.ui.notify(`Backup complete! (${fileCount} files, ${(body.length / 1000).toFixed(1)} KB)`, 'S');
    },
  };

  tw.events.override('backup.save', tw.macros.backup.save);
  tw.events.override('backup.restore', tw.macros.backup.restore);

  function readConfig() {
    let settings = tw.call('getJSONObject', '$GeneralSettings');
    if (!settings || !settings.backup?.Gist?.accessToken) {
      tw.ui.notify('No Gist accessToken found in $GeneralSettings.backup.Gist!', 'W');
      return null;
    }
    return {
      accessToken: settings.backup.Gist.accessToken,
      gistId: settings.backup.Gist.gistId || '',
      description: settings.backup.Gist.description || DEFAULT_DESCRIPTION,
    };
  }

  async function fetchRemoteFiles(cfg) {
    let res = await fetch('https://api.github.com/gists/' + cfg.gistId, {headers: authHeaders(cfg.accessToken)});
    if (!res.ok) {
      console.error('GistBackup fetch-before-patch', await readError(res));
      tw.ui.notify(`Backup failed '${res.status}' (see log)`, 'E');
      return null;
    }
    let gist = await res.json();
    return gist.files || {};
  }

  function persistGistId(newId) {
    let tiddler = tw.run.getTiddler('$GeneralSettings');
    let parsed = {};
    try {parsed = JSON.parse(tiddler.text || '{}');} catch {}
    if (!parsed.backup) parsed.backup = {};
    if (!parsed.backup.Gist) parsed.backup.Gist = {};
    parsed.backup.Gist.gistId = newId;
    tiddler.text = JSON.stringify(parsed, null, 2);
    delete tiddler.doNotSave;
    tw.run.updateTiddlerHard('$GeneralSettings', tiddler);
    tw.events.send('save.silent');
  }

  function rebuildTiddlersFromGist(gist) {
    let all = [];
    let visible = [];
    let trashed = [];
    let sawMeta = false;
    Object.entries(gist.files || {}).forEach(([name, file]) => {
      if (name === META_FILENAME) {
        try {
          let meta = JSON.parse(file.content);
          visible = Array.isArray(meta.visible) ? meta.visible : [];
          trashed = Array.isArray(meta.trashed) ? meta.trashed : [];
          sawMeta = true;
        } catch (e) {
          console.warn('GistBackup: failed to parse', META_FILENAME, e.message);
        }
        return;
      }
      if (name.startsWith('_')) return;
      if (!name.endsWith('.json')) return;
      try {
        all.push(JSON.parse(file.content));
      } catch (e) {
        console.warn(`GistBackup: skipping malformed file '${name}':`, e.message);
      }
    });
    if (!sawMeta) console.warn(`GistBackup: no ${META_FILENAME} in gist — visible/trashed will be empty`);
    return {all, visible, trashed};
  }

  function tiddlerFilename(title) {
    // encodeURIComponent gives a stable, reversible mapping that is safe as a
    // Gist filename (no '/', no empty result for non-empty input).
    return encodeURIComponent(title) + '.json';
  }

  function authHeaders(token) {
    return {
      'Authorization': 'Bearer ' + token,
      'Accept': 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    };
  }

  function mutationHeaders(token) {
    return Object.assign(authHeaders(token), {'Content-Type': 'application/json'});
  }

  async function readError(res) {
    let body = '';
    try {body = await res.text();} catch {}
    return `${res.status} ${res.statusText}${body ? ': ' + body.slice(0, 200) : ''}`;
  }

})();

tw.extensions.registerPlugin('base', 'GithubSaver', () => {
  return {
    name: 'GithubSaver',
    version: '0.0.2',
    init() {
    },
    start() {
    },
    async save({text, token, repo, path, filename, commitMessage, branch, endpoint}) {
    //
      branch = branch || 'main';
      endpoint = endpoint || 'https://api.github.com';
      commitMessage = 'TWikki Save ' + new Date().toISOString();

      validate({text, token, repo, path, filename, commitMessage});

      const headers = {
        'Accept': 'application/vnd.github.v3+json',
        'Content-Type': 'application/json;charset=UTF-8',
        'Authorization': 'Bearer ' + token,
        'If-None-Match': '',
      };

      // Normalize path with trailing slash
      if (path.substring(0, 1) !== '/') path = '/' + path;
      if (path.substring(path.length - 1) !== '/') path = path + '/';

      // List Files
      const listUrl = endpoint + '/repos/' + repo + '/contents' + path;
      let res = await fetch(listUrl, {
        method: 'GET',
        headers: headers,
        data: {
          ref: branch,
        },
      });

      if (res.ok) throw new Error(`GitHubSaver.save() GET files failed ${res.status} for ${listUrl}`);

      // Find the sha of the file if it exists
      const files = await res.json();
      const sha = files.find(file => file.name === filename);

      const data = {
        message: commitMessage,
        content: btoa(text),
        branch: branch,
        sha: sha,
      };

      // Perform a PUT request to save the file
      let putUrl = listUrl + filename;
      res = await fetch(putUrl, {
        method: 'PUT',
        headers: headers,
        data: JSON.stringify(data),
      });
      if (res.ok) throw new Error(`GitHubSaver.save() PUT file failed ${res.status} for ${putUrl}`);

      function validate(obj) {
        Object.keys.forEach(k => {
          if (!obj[k]) throw new Error(`GitHubSaver.save() missing parameter '${k}'!`);
        });
      }

    },
  };
});

