/**
 * ## Description
 * $SynchDataFunctions
 * Synchronise your data with a private [GitHub Gist](https://gist.github.com).
 * Each tiddler is stored as a separate file so changes appear as per-tiddler
 * diffs in the gist's history. A sidecar `_twikki.meta.json` holds the visible
 * list. On first push (when no gistId is configured) a new private gist is
 * created and its id is written back to `$GeneralSettings`.
 *
 * Tiddlers tagged `$NoBackup` (or the legacy `$NoSynch`) are never pushed.
 *
 * Required `$GeneralSettings` shape:
 * ```json
 * {
 *   "synch": {
 *     "Gist": {
 *       "accessToken": "ghp_xxx",
 *       "gistId": "",
 *       "description": "TWikki sync"
 *     }
 *   }
 * }
 * ```
 * The PAT must have the `gist` scope.
 *
 * ### Release Notes
 * * v2.0.0
 *   * Migrated from to GitHub Gist (per-tiddler history, 10 MB per file)
 *   * Honour `$NoBackup` tag in addition to `$NoSynch`
 * * v1.0.9
 *   * Don't synch trashed tiddlers
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 2.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
// TODO: Pull force, clearing local
// TODO: Selective Synch: Include/Exclude Tags/Packages
tw.macros.synch = (function(){

  const META_FILENAME = '_twikki.meta.json';
  const FORMAT = 'twikki-sync-v1';
  const DEFAULT_DESCRIPTION = 'TWikki sync';

  const isNoPush = t => t.tags?.includes('$NoSynch') || t.tags?.includes('$NoBackup');

  tw.events.override('synch.full', doFull);
  tw.events.override('synch.push', doPush);
  tw.events.override('synch.pull', doPull);
  tw.events.override('synch.upload', doUpload);
  return {
    // <<synch.full>>: Push/pull to/from remote
    full() {
      return tw.ui.button('{{$IconSynch}}', 'synch.full', null, 'btn-synch', 'title="Synch Data"');
    },
    // <<synch.test>>: Simulate push/pull to/from remote
    test() {
      return '<button onclick="tw.macros.synch.doTest()">Synch Test</button>';
    },
    // <<synch.pull>>: Only import from remote
    pull() {
      return tw.ui.button('{{$IconPull}}', 'synch.pull', null, 'btn-synch-pull', 'title="Pull Synched Data"');
    },
    // <<synch.push>>: Only write to remote
    push() {
      return tw.ui.button('{{$IconPush}}', 'synch.push', null, 'btn-synch-push', 'title="Push Synched Data"');
    },
    // <<synch.upload>>: Overwrite remote from local
    upload() {
      return tw.ui.button('{{$IconPush}}', 'synch.upload', null, 'btn-synch-upload', 'title="Upload Data"', 'purple');
    },
    // TODO: Delete all local and pull (restore)
  };

  async function doFull() {
    return await synch({pull: true, push: true});
  }
  async function doPull() {
    return await synch({pull: true, push: false});
  }
  async function doPush() {
    return await synch({pull: false, push: true});
  }
  async function doUpload() {
    return await synch({pull: false, push: true, fetchRemote: false});
  }
  async function synch({fetchRemote = true, push = true, pull = true, dryRun = false}) {

    if (!push && !pull) throw new Error('SynchDataFunctions: Please supply push or pull parameters!');

    let settings = tw.call('getJSONObject', '$GeneralSettings');
    if (!settings || !settings.synch?.Gist?.accessToken) return tw.ui.notify('No Gist accessToken found in $GeneralSettings.synch.Gist!', 'W');
    const cfg = {
      accessToken: settings.synch.Gist.accessToken,
      gistId: settings.synch.Gist.gistId || '',
      description: settings.synch.Gist.description || DEFAULT_DESCRIPTION,
    };

    // Fetch remote
    let remoteTiddlers = [];
    let remoteTrashedTiddlers = [];
    if (fetchRemote && cfg.gistId) {
      let res = await fetch('https://api.github.com/gists/' + cfg.gistId, {headers: authHeaders(cfg.accessToken)});
      if (!res.ok) {
        console.error('SynchData fetch', await readError(res));
        return tw.ui.notify(`Fetch remote failed '${res.status}' (see log)`, 'E');
      }
      let gist = await res.json();
      let rebuilt = rebuildTiddlersFromGist(gist);
      remoteTiddlers = rebuilt.all;
      // We never push/pull trashed — it's local-only information.
    }
    // If cfg.gistId is empty we treat remote as empty — first push will POST a new gist.

    let log = [];
    let remote = {create: [], update: [], delete: []};
    let local = {create: [], update: [], delete: []};

    let localTiddlers = tw.tiddlers.all
      .filter(t => !t.isRawShadow); // Don't synch raw shadows - See BUG below

    remoteTiddlers.forEach(remoteTiddler => {
      remoteTiddler.created = new Date(remoteTiddler.created);
      remoteTiddler.updated = new Date(remoteTiddler.updated);
      let localTiddler = localTiddlers.find(t => t.title === remoteTiddler.title);
      if (isNoPush(remoteTiddler) || (localTiddler && isNoPush(localTiddler))) return log.push(`Skipping no-push tiddler [[${localTiddler?.title || remoteTiddler.title}]]`);
      if (localTiddler?.doNotSave) return log.push(`Skipping doNotSave tiddler [[${localTiddler.title}]]`);
      // if (remoteTiddler.title.match(/SynchLog/)) debugger;
      // TODO: BUG: Deleted local shadow tiddler is pulled in from remote
      let deletedLocalTiddler = tw.tiddlers.trashed.find(t => t.title === remoteTiddler.title);
      let deletedLocally = !localTiddler && deletedLocalTiddler?.updated > remoteTiddler.updated;
      let createdRemotely = !localTiddler && !deletedLocally;
      let updatedLocally = localTiddler?.updated > remoteTiddler.updated;
      let updatedRemotely = remoteTiddler.updated > localTiddler?.updated;
      if (deletedLocally) {
        // Delete Remote
        if (push) remote.delete.push(deletedLocalTiddler.title);
      } else if (createdRemotely) {
        // Restore Local: Updated remotely after local delete
        if (pull) {
          if (!dryRun) tw.run.addTiddler(remoteTiddler);
          local.create.push(remoteTiddler.title);
          log.push(`Created local tiddler [[${remoteTiddler.title}]]`);
        }
      } else if (updatedLocally) {
        // Local update is newer
        if (push) remote.update.push(localTiddler.title); // 👈
      } else if (updatedRemotely) {
        // Remote update is newer
        if (push) {
          if (!dryRun) tw.run.updateTiddlerHard(remoteTiddler.title, remoteTiddler);
          local.update.push(remoteTiddler.title);
          log.push(`Updated local tiddler [[${localTiddler.title}]]`); // 👈
        }
      }
    });

    localTiddlers.forEach(localTiddler => {
      if (isNoPush(localTiddler)) return log.push(`Skipping no-push tiddler [[${localTiddler.title}]]`);
      if (localTiddler?.doNotSave) return log.push(`Skipping doNotSave tiddler [[${localTiddler.title}]]`);
      let remoteTiddler = remoteTiddlers.find(t => t.title === localTiddler.title);
      if (remoteTiddler) {
        remoteTiddler.created = new Date(remoteTiddler.created);
        remoteTiddler.updated = new Date(remoteTiddler.updated);
      }
      let deletedRemoteTiddler = remoteTrashedTiddlers.find(t => t.title === localTiddler.title);
      let deletedRemotely = !remoteTiddler && deletedRemoteTiddler?.updated > localTiddler.updated;
      let createdLocally = !remoteTiddler && !deletedRemotely;
      if (deletedRemotely) {
        // Delete Locally
        if (pull) {
          if (!dryRun) tw.run.deleteTiddler(localTiddler.title, true);
          local.delete.push(remoteTiddler.title);
          log.push(`Deleted local tiddler [[${localTiddler.title}]]`);
        }
      } else if (createdLocally) {
        if (push) remote.create.push(localTiddler.title);
      }
      // Updated locally/remotely handled above ☝️
    });

    if (remote.create.length + remote.update.length + remote.delete.length +
      local.create.length + local.update.length + local.delete.length === 0
    ) return tw.ui.notify('No changes to synch', 'S');

    if (push) {
      // Perform remote updates
      remote.create.forEach(title => {
        log.push(`Created remote tiddler [[${title}]]`);
      });
      remote.update.forEach(title => {
        log.push(`Updated remote tiddler [[${title}]]`);
      });
      remote.delete.forEach(title => {
        log.push(`Deleted remote tiddler [[${title}]]`);
      });
    }

    let logTiddler = {
      title: `$SynchLog ${new Date().toISOString()}`,
      text: logSummary(local, remote) + '\n\n## Log\n' + log.join('  \n') + '',
      tags: ['$SynchLog'],
      type: 'x-twikki',
    };

    if (push && !dryRun) {
      // Build a Gist files patch: create/update → {content}, delete → null.
      const byTitle = Object.fromEntries(
        localTiddlers.filter(t => !isNoPush(t)).map(t => [t.title, t])
      );
      const files = {};
      [...remote.create, ...remote.update].forEach(title => {
        const t = byTitle[title];
        if (t) files[tiddlerFilename(title)] = {content: JSON.stringify(t, null, 2)};
      });
      remote.delete.forEach(title => {
        files[tiddlerFilename(title)] = null;
      });
      files[META_FILENAME] = {content: JSON.stringify({
        format: FORMAT,
        visible: tw.tiddlers.visible,
      }, null, 2)};

      let res;
      if (cfg.gistId) {
        res = await fetch('https://api.github.com/gists/' + cfg.gistId, {
          method: 'PATCH',
          headers: mutationHeaders(cfg.accessToken),
          body: JSON.stringify({files, description: cfg.description}),
        });
      } else {
        res = await fetch('https://api.github.com/gists', {
          method: 'POST',
          headers: mutationHeaders(cfg.accessToken),
          body: JSON.stringify({public: false, description: cfg.description, files}),
        });
      }

      if (!res.ok) {
        logTiddler.title = 'Failed: ' + logTiddler.title;
        tw.run.previewTiddler(logTiddler);
        console.error('SynchData push', await readError(res));
        return tw.ui.notify(`Synch (push) to remote failed '${res.status}' (see log)`, 'E');
      }
      if (!cfg.gistId) {
        let created = await res.json();
        persistGistId(created.id);
        tw.ui.notify(`New sync gist created (${created.id}) and saved to $GeneralSettings`, 'I');
      }
    }

    // Rebooting here is left up to the user
    //  we cannot know what has changed

    if (push && pull) {
      tw.ui.notify('Synch (full) complete!', 'S');
    } else if (pull) {
      tw.ui.notify('Synch (pull) complete!', 'S');
    } else if (push) {
      tw.ui.notify('Synch (push) complete!', 'S');
    }

    tw.run.previewTiddler(logTiddler);

    function logSummary(local, remote) {
      return `
## Local
* Created (${local.create.length}) ${local.create.length ? ':\n  * [[' + local.create.join(']]\n  * [[') + ']]\n' : ''}
* Updated (${local.update.length}) ${local.update.length ? ':\n  * [[' + local.update.join(']]\n  * [[') + ']]\n' : ''}
* Deleted (${local.delete.length}) ${local.delete.length ? ':\n  * [[' + local.delete.join(']]\n  * [[') + ']]\n' : ''}
## Remote
* Created (${remote.create.length}) ${remote.create.length ? ':\n  * [[' + remote.create.join(']]\n  * [[') + ']]\n' : ''}
* Updated (${remote.update.length}) ${remote.update.length ? ':\n  * [[' + remote.update.join(']]\n  * [[') + ']]\n' : ''}
* Deleted (${remote.delete.length}) ${remote.delete.length ? ':\n  * [[' + remote.delete.join(']]\n  * [[') + ']]\n' : ''}
`.trim();
    }
  }

  // --- Gist helpers (duplicated from $GistBackupPlugin to keep this plugin self-contained) ---

  function rebuildTiddlersFromGist(gist) {
    let all = [];
    let visible = [];
    let sawMeta = false;
    Object.entries(gist.files || {}).forEach(([name, file]) => {
      if (name === META_FILENAME) {
        try {
          let meta = JSON.parse(file.content);
          visible = Array.isArray(meta.visible) ? meta.visible : [];
          sawMeta = true;
        } catch (e) {
          console.warn('SynchData: failed to parse', META_FILENAME, e.message);
        }
        return;
      }
      if (name.startsWith('_')) return;
      if (!name.endsWith('.json')) return;
      try {
        all.push(JSON.parse(file.content));
      } catch (e) {
        console.warn(`SynchData: skipping malformed file '${name}':`, e.message);
      }
    });
    if (!sawMeta) console.debug(`SynchData: no ${META_FILENAME} in gist — visible will be empty`);
    return {all, visible, trashed: []};
  }

  function tiddlerFilename(title) {
    return encodeURIComponent(title) + '.json';
  }

  function authHeaders(token) {
    return {
      'Authorization': 'Bearer ' + token,
      'Accept': 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    };
  }

  function mutationHeaders(token) {
    return Object.assign(authHeaders(token), {'Content-Type': 'application/json'});
  }

  async function readError(res) {
    let body = '';
    try {body = await res.text();} catch {}
    return `${res.status} ${res.statusText}${body ? ': ' + body.slice(0, 200) : ''}`;
  }

  function persistGistId(newId) {
    let tiddler = tw.run.getTiddler('$GeneralSettings');
    let parsed = {};
    try {parsed = JSON.parse(tiddler.text || '{}');} catch {}
    if (!parsed.synch) parsed.synch = {};
    if (!parsed.synch.Gist) parsed.synch.Gist = {};
    parsed.synch.Gist.gistId = newId;
    tiddler.text = JSON.stringify(parsed, null, 2);
    delete tiddler.doNotSave;
    tw.run.updateTiddlerHard('$GeneralSettings', tiddler);
    tw.events.send('save.silent');
  }

})();

/**
 * ## Description
 * Obsidian-style tabs for open notes. The platform keeps rendering every
 * visible note as a `.tiddler` element inside `#visible-tiddlers`; this plugin
 * adds a tab strip (`#tab-strip`) and shows only the *active* note by toggling
 * a `.tab-active` class (the show/hide CSS lives in `$StyleSheetCore`, gated
 * behind the `.tabbed` class this plugin adds — so without the plugin notes
 * just stack as before).
 *
 * Exposes `tw.tabs = {active, rebuild(), activate(title)}`. Explorer / search /
 * command-palette call `tw.tabs.activate(title)` after `tiddler.show` because
 * re-opening an already-open note does not re-render it.
 *
 * Sync: render events are coalesced in a microtask. A single-note open
 * activates that note; a bulk re-render (open-all / close) keeps the prior
 * active tab, or — when the active note was closed — activates its neighbour.
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
(function() {

  let strip; // #tab-strip
  let vis; // #visible-tiddlers
  let app; // #app (carries the mode-tabs / mode-river class)
  let mode = 'tabs'; // 'tabs' | 'river' — from $GeneralSettings.layout.mode
  let lastVisible = [];
  let batch = [];
  let scheduled = false;
  let scrollPos = {}; // remembered scrollTop per note title

  wireUp('ui.loaded', init);
  wireUp('ui.reloaded', init);

  function init() {
    strip = document.getElementById('tab-strip');
    vis = document.getElementById('visible-tiddlers');
    app = document.getElementById('app');
    if (!strip || !vis) return;
    mode = layoutMode();
    scrollPos = {};
    tw.tabs = {active: null, rebuild: () => schedule(), activate};

    if (app) {
      app.classList.toggle('mode-river', mode !== 'tabs');
      app.classList.toggle('mode-tabs', mode === 'tabs');
    }

    if (mode === 'river') {
      // No tabs: let every open note stack (the .tabbed show/hide rule is off).
      vis.classList.remove('tabbed');
      strip.innerHTML = '';
      vis.querySelectorAll(':scope > .tiddler.tab-active').forEach(el => el.classList.remove('tab-active'));
      return;
    }

    vis.classList.add('tabbed');
    if (!strip._tabsBound) {
      strip._tabsBound = true;
      strip.addEventListener('click', onStripClick);
    }
    lastVisible = tw.tiddlers.visible.slice();
    flush();
  }

  function layoutMode() {
    try {
      return tw.run.getJSONObject('$GeneralSettings')?.layout?.mode === 'tabs' ? 'tabs' : 'river';
    } catch {
      return 'tabs';
    }
  }

  // Re-apply when the layout mode changes (raw edit emits tiddler.modified; the
  // settings form saves via updateTiddlerHard + save.silent). Cheap; only re-inits
  // when the mode actually flips.
  ['save.silent', 'tiddler.modified', 'tiddler.updated'].forEach(ev => wireUp(ev, refreshMode));
  function refreshMode() {
    if (layoutMode() !== mode) init();
  }

  wireUp('tiddler.rendered', ({tiddler}) => {batch.push(tiddler.title); schedule();});
  wireUp('story.rendered', schedule);
  wireUp('story.changed', schedule);
  // Focus a note's tab when it's requested while already open (link/hash/search):
  // showTiddler early-returns in that case and emits `tiddler.refocus` instead of
  // re-rendering. (Newly-opened notes are handled via `tiddler.rendered` above.)
  wireUp('tiddler.refocus', activate);

  function schedule() {
    if (scheduled) return;
    scheduled = true;
    Promise.resolve().then(flush);
  }

  function flush() {
    scheduled = false;
    if (mode !== 'tabs' || !strip || !vis) {batch = []; return;}
    let rendered = batch; batch = [];
    let visible = tw.tiddlers.visible;
    let active = tw.tabs ? tw.tabs.active : null;

    if (rendered.length === 1 && visible.includes(rendered[0])) {
      // Single note just opened → make it active.
      active = rendered[0];
    } else if (!visible.includes(active)) {
      // Active note is gone (closed) → activate its neighbour.
      let idx = lastVisible.indexOf(active);
      if (idx < 0) idx = visible.length - 1;
      active = visible[Math.min(idx, visible.length - 1)] || visible[visible.length - 1] || null;
    }

    if (tw.tabs) tw.tabs.active = active;
    rebuildStrip(visible, active);
    applyActive(active);
    restoreScroll(active);
    // Forget scroll for notes that are no longer open.
    Object.keys(scrollPos).forEach(t => {if (!visible.includes(t)) delete scrollPos[t];});
    lastVisible = visible.slice();
  }

  function activate(title) {
    if (mode !== 'tabs' || !title) return;
    saveScroll(); // capture the outgoing note's position before it hides
    if (tw.tabs) tw.tabs.active = title;
    applyActive(title);
    rebuildStrip(tw.tiddlers.visible, title);
    restoreScroll(title);
  }

  // Persist/restore scroll position so switching tabs and back keeps your place.
  function saveScroll() {
    if (vis && tw.tabs && tw.tabs.active != null) scrollPos[tw.tabs.active] = vis.scrollTop;
  }

  function restoreScroll(title) {
    if (vis) vis.scrollTop = scrollPos[title] || 0;
  }

  function rebuildStrip(visible, active) {
    if (!strip) return;
    strip.innerHTML = visible.map(title => `
      <div class="tab${title === active ? ' active' : ''}" data-tab="${attr(title)}" title="${attr(title)}">
        <span class="tab-label">${esc(label(title))}</span>
        <button class="tab-close icon" data-msg="tiddler.close" data-param="${attr(title)}" title="Close">✕</button>
      </div>`).join('') +
      '<button class="tab-new icon" data-msg="tiddler.new" title="New note">+</button>';
  }

  function applyActive(active) {
    if (!vis) return;
    vis.querySelectorAll(':scope > .tiddler').forEach(el => {
      el.classList.toggle('tab-active', el.getAttribute('data-tiddler-title') === active);
    });
    if (strip) strip.querySelectorAll('.tab').forEach(t => {
      t.classList.toggle('active', t.getAttribute('data-tab') === active);
    });
  }

  function onStripClick(e) {
    if (e.target.closest('.tab-close')) return; // close handled by platform data-msg
    let tab = e.target.closest('.tab');
    if (tab) activate(tab.getAttribute('data-tab'));
  }

  function label(title) {
    return title.replace(/^\$/, '');
  }

  function attr(s) {
    return String(s).replace(/&/g, '&amp;').replace(/"/g, '&quot;');
  }

  function esc(s) {
    return tw.core.common.escapeHtml(String(s));
  }

  function wireUp(event, handler) {
    tw.events.subscribe(event, handler, 'TabsPlugin');
  }

})();

/**
 * ## Description
 * Import themes from a fixed, public [GitHub Gist](https://gist.github.com).
 * The gist ships a packaged `themes.json` (`{tiddlers: [...]}`) containing,
 * for each theme, an `XStyleSheet` (type `css`, tagged `$StyleSheet`) and an
 * `XTheme` wrapper (tagged `$Theme`). The importer fetches that package and
 * opens a dialog where the user can:
 *   - tick which themes to import (checkbox), and
 *   - optionally pick a single theme to apply (radio).
 * Importing overwrites any local tiddler of the same name. Applying a theme
 * also imports it (apply implies import). After import the selected theme,
 * if any, is applied via the `theme.switch` event.
 *
 * The gist URL is read from `$GeneralSettings.themes.importUrl`; if absent a
 * built-in default is used. The dialog shows this URL in an editable field and
 * reloads the theme list whenever it is changed. The URL may point either at
 * the raw `themes.json` (returns `{tiddlers}` directly) or at the gist API
 * endpoint (returns a `{files}` wrapper) — both shapes are handled.
 *
 * Surfaced via the `<<themeImport.button>>` macro (rendered next to the theme
 * selector in `$Themes`) and the `theme.import` event.
 */
/**
 * ## Data
 * ```json
 * {
 *   "version": 1.0.0
 * }
 * ```
 */
// ## Code
// ```javascript
(function() {

  const DIALOG_ID = 'theme-import-dialog';
  const DEFAULT_URL = 'https://gist.githubusercontent.com/cawoodm/c43037e0370393ef2928848fee64e95d/raw/themes.json';

  tw.macros.themeImport = {
    button() {
      return tw.ui.button('{{$IconPull}}', 'theme.import', null, 'theme-import-btn', 'title="Import Themes"');
    },
  };

  tw.events.subscribe('theme.import', open, 'ThemeImporter');

  function open() {
    showDialog(importUrl());
  }

  async function fetchPackage(url) {
    let res;
    try {
      res = await fetch(url, {cache: 'no-store'});
    } catch (e) {
      console.error('ThemeImporter fetch', e);
      return null;
    }
    if (!res.ok) {
      console.error('ThemeImporter fetch', res.status, res.statusText);
      return null;
    }
    let parsed;
    try {
      parsed = await res.json();
    } catch (e) {
      console.error('ThemeImporter parse', e);
      return null;
    }
    let pkg = unwrap(parsed);
    if (!pkg || !Array.isArray(pkg.tiddlers)) {
      console.error('ThemeImporter: no tiddlers found in package');
      return null;
    }
    return pkg.tiddlers;
  }

  // Accept either the raw package ({tiddlers}) or the gist API shape ({files}).
  function unwrap(parsed) {
    if (parsed && Array.isArray(parsed.tiddlers)) return parsed;
    if (parsed && parsed.files) {
      let file = parsed.files['themes.json']
        || Object.values(parsed.files).find(f => f.filename?.endsWith('.json'));
      if (!file) return null;
      try {return JSON.parse(file.content);} catch {return null;}
    }
    return null;
  }

  function importUrl() {
    let settings = tw.call('getJSONObject', '$GeneralSettings');
    return settings?.themes?.importUrl || DEFAULT_URL;
  }

  function showDialog(url) {
    let existing = document.getElementById(DIALOG_ID);
    if (existing) existing.remove();

    let dialog = document.createElement('dialog');
    dialog.id = DIALOG_ID;
    dialog.innerHTML = dialogHtml(url);
    document.body.appendChild(dialog);

    let form = dialog.querySelector('form');
    let urlInput = form.querySelector('#theme-import-url');
    let state = {byTitle: new Map()}; // re-populated by refreshList on every load
    let close = () => {dialog.close(); dialog.remove();};
    let refresh = () => refreshList(form, urlInput.value.trim(), state);

    // Reload the theme list whenever the URL changes.
    urlInput.addEventListener('change', refresh);
    urlInput.addEventListener('keydown', e => {
      if (e.key === 'Enter') {e.preventDefault(); refresh();}
    });
    form.querySelector('#theme-import-load').addEventListener('click', e => {
      e.preventDefault();
      refresh();
    });

    form.querySelector('#theme-import-go').addEventListener('click', e => {
      e.preventDefault();
      let toImport = [...form.querySelectorAll('input[name="import"]:checked')].map(i => i.value);
      let applyTitle = form.querySelector('input[name="apply"]:checked')?.value || '';
      if (applyTitle && !toImport.includes(applyTitle)) toImport.push(applyTitle);
      close();
      if (!toImport.length) return tw.ui.notify('No themes selected', 'W');
      doImport(toImport, applyTitle, state.byTitle);
    });
    form.querySelector('#theme-import-cancel').addEventListener('click', e => {
      e.preventDefault();
      close();
    });

    dialog.showModal();
    refresh(); // initial load
  }

  // Fetch the package at `url` and (re)render the theme list inside the dialog.
  async function refreshList(form, url, state) {
    let box = form.querySelector('#theme-import-listbox');
    state.byTitle = new Map();
    if (!url) return status(box, 'Enter a themes.json URL.');
    status(box, 'Loading…');
    let tiddlers = await fetchPackage(url);
    if (!tiddlers) return status(box, 'Failed to load themes (see log).', true);
    state.byTitle = new Map(tiddlers.map(t => [t.title, t]));
    let themes = tiddlers.filter(t => t.tags?.includes('$Theme'));
    if (!themes.length) return status(box, 'No themes found in this package.');
    box.innerHTML = listHtml(themes);
    // Applying a theme implies importing it.
    form.querySelectorAll('input[name="apply"]').forEach(radio => {
      radio.addEventListener('change', () => {
        if (!radio.value) return;
        let cb = form.querySelector(`input[name="import"][value="${cssEscape(radio.value)}"]`);
        if (cb) cb.checked = true;
      });
    });
  }

  function status(box, msg, isError) {
    box.innerHTML = `<p class="theme-import-status${isError ? ' error' : ''}">${escapeHtml(msg)}</p>`;
  }

  function dialogHtml(url) {
    return `
      <form id="theme-import-form">
        <h3>Import Themes</h3>
        <div class="theme-import-url">
          <input type="url" id="theme-import-url" value="${attr(url)}" placeholder="themes.json URL" size="60">
          <button id="theme-import-load" formnovalidate>Load</button>
        </div>
        <div id="theme-import-listbox"></div>
        <div class="toolbar">
          <button id="theme-import-go">Import</button>
          <button id="theme-import-cancel" formnovalidate>Cancel</button>
        </div>
      </form>`;
  }

  function listHtml(themes) {
    let rows = themes.map((t, i) => `
      <tr>
        <td><input type="checkbox" name="import" value="${attr(t.title)}" id="ti-imp-${i}"></td>
        <td><input type="radio" name="apply" value="${attr(t.title)}" id="ti-app-${i}"></td>
        <td><label for="ti-imp-${i}">${escapeHtml(displayName(t.title))}</label></td>
      </tr>`).join('');
    return `
      <table class="theme-import-list">
        <thead><tr><th>Import</th><th>Apply</th><th>Theme</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
      <label class="theme-import-none">
        <input type="radio" name="apply" value="" checked> Apply: none
      </label>`;
  }

  function doImport(titles, applyTitle, byTitle) {
    let imported = new Set();
    titles.forEach(themeTitle => {
      let theme = byTitle.get(themeTitle);
      if (!theme) return;
      let sheets = referencedTitles(theme).filter(s => byTitle.has(s));
      [theme, ...sheets.map(s => byTitle.get(s))].forEach(t => {
        if (imported.has(t.title)) return;
        upsert(t);
        imported.add(t.title);
      });
    });
    tw.events.send('save.silent');
    if (applyTitle) tw.events.send('theme.switch', applyTitle);
    let suffix = applyTitle ? `, applied '${displayName(applyTitle)}'` : '';
    tw.ui.notify(`Imported ${titles.length} theme(s), ${imported.size} tiddler(s)${suffix}`, 'S');
  }

  function upsert(tiddler) {
    let copy = {...tiddler};
    tw.run.updateTiddlerHard(copy.title, copy); // upsert: adds if new, overwrites if present
    tw.events.send('tiddler.updated', copy.title); // let CoreThemeManager refresh the selector
  }

  function referencedTitles(themeTiddler) {
    let out = [];
    let re = /\[\[([^\]]+)\]\]/g;
    let m;
    while ((m = re.exec(themeTiddler.text || ''))) out.push(m[1]);
    return out;
  }

  function displayName(title) {
    return title.replace(/(^\$)|(Theme$)/g, '');
  }

  function attr(s) {
    return String(s).replace(/&/g, '&amp;').replace(/"/g, '&quot;');
  }

  function escapeHtml(s) {
    return tw.core.common.escapeHtml(String(s));
  }

  // Escape a value for use inside a CSS attribute selector.
  function cssEscape(s) {
    return String(s).replace(/(["\\])/g, '\\$1');
  }

})();

(function(){

  tw.macros.core.TrashCanIcon = () => {
    let count = tw.tiddlers.trashed.length;
    return tw.ui.button('{{$IconDelete}}', 'tiddler.show', '$TrashManager', 'trashCanIcon', `title="${count} trashed tiddlers"`);
  // return `<a id="trashCanIcon" href="#$TrashManager">🗑️ (${count})</a>`;
  };
  tw.macros.core.TrashEmptyButton = () => {
    return tw.ui.button('Empty Trash', 'tiddlers.trashed.empty', null, 'trashButton');
  };
  tw.macros.core.TrashCanStatus = () => {
    return `<span id="trashStatus">${tw.tiddlers.trashed.length} tiddlers in the [trash can](#$TrashedTiddlers)!`;
  };
  tw.events.subscribe('tiddlers.trashed.empty', emptyTrash);
  function emptyTrash() {
    if (!confirm('Are you sure you want to permanently deleted your trashed tiddlers?')) return;
    tw.tiddlers.trashed = [];
    trashCanRefresh();
    tw.run.save();
  };
  tw.macros.core.TrashCanContents = () => {
    const list = tw.tiddlers.trashed.map(t => (`<li><a data-msg="tiddlers.trashed.preview" data-param="${t.title}">${t.title}</a> 
      <a title="Restore Tiddler" data-msg="tiddler.trashed.restore" data-param="${t.title}">🚮</a></li>`)).join('\n');
    return `<ul id="trashContents">${list}</ul>`;
  };
  tw.events.subscribe('tiddlers.trashed.preview', trashPreview);
  function trashPreview(title) {
    let tiddler = tw.tiddlers.trashed.find(t => t.title === title);
    tw.run.previewTiddler(tiddler, tw.templates.TiddlerTrashed);
  };

  tw.events.subscribe('tiddler.trashed.destroy', removeTiddlerFromTrash);
  function removeTiddlerFromTrash(title) {
    if (!confirm('Are you sure you want to permanently delete your trashed tiddler?')) return;
    let tiddlerIndex = tw.tiddlers.trashed.findIndex(t => t.title === title);
    tw.tiddlers.trashed.splice(tiddlerIndex, 1);
    trashCanRefresh();
    tw.core.dom.preview.close();
    tw.run.save();
  };

  tw.events.subscribe('tiddler.deleted', trashCanRefresh);
  tw.events.subscribe('trash.refresh', trashCanRefresh);
  function trashCanRefresh() {
    if (tw.core.dom.$('trashContents')) tw.core.dom.$('trashContents').outerHTML = tw.lib.markdown(tw.macros.core.TrashCanContents());
    if (tw.core.dom.$('trashCanIcon')) tw.core.dom.$('trashCanIcon').innerHTML = tw.macros.core.TrashCanIcon();
    if (tw.core.dom.$('trashStatus')) tw.core.dom.$('trashStatus').outerHTML = tw.lib.markdown(tw.macros.core.TrashCanStatus());
    tw.run.rerenderTiddler('$TrashedTiddlers');
  };

  tw.events.subscribe('tiddler.trashed.restore', restoreTiddlerFromTrash);
  function restoreTiddlerFromTrash(title) {
    if (!confirm('Are you sure you want to restore your trashed tiddler? This may overwrite an existing tiddler!')) return;
    let tiddler = tw.tiddlers.trashed.find(t => t.title === title);
    tw.run.addTiddler(tiddler);
    tw.run.reload();
    // So styles, search list etc update
    let tiddlerIndex = tw.tiddlers.trashed.findIndex(t => t.title === title);
    tw.tiddlers.trashed.splice(tiddlerIndex, 1);
    trashCanRefresh();
    tw.run.save();
  };
})();

tw.macros.core.WorkspaceSelect = () => {
  let workspace = tw.storage.get('workspace');
  return `<select id="workspace-select" onchange="tw.events.send('workspace.load.prompt', this.value);">
    <option value=""> - new workspace -</option>
    ${tw.storage.get('workspaces').map(n => `<option value="${n}"${n === workspace ? ' selected' : ''}>${n}</option>`).join('\n')}
  </select>`;
};
tw.macros.core.WorkspaceCreate = () => {
  return tw.ui.button('Create Workspace', 'workspace.create.prompt');
};
if (!tw.tmp.workspaceEvents) {
  tw.tmp.workspaceEvents = 1;
  tw.events.subscribe('workspace.load.prompt', (workspace) => {
    if (!workspace) workspace = tw.events.send('workspace.create.prompt')[0];
    if (!workspace) return;
    tw.events.send('workspace.load', workspace);
  }, 'WorkspaceWidgets');
  tw.events.subscribe('workspace.create.prompt', () => {
    let workspace = prompt('Enter name for new workspace:');
    if (!workspace) return;
    if (confirm('Would you like to clone this workspace?'))
      tw.events.send('workspace.clone', workspace);
    else
      tw.events.send('workspace.create', workspace);
    tw.core.dom.$('workspace-select').innerHTML = tw.macros.core.WorkspaceSelect();
    // tw.events.subscribe('tiddler.refresh', '$Workspaces'); // TODO: Dynamically get currentTiddler above?
    return workspace;
  }, 'WorkspaceWidgets');
}

// https://www.jsdelivr.com/package/npm/highlight.js
// https://cdnjs.com/libraries/highlight.js

(function(){
  tw.events.subscribe('ui.loaded', () => {
    tw.core.dom.addStyleSheet('highlight-light', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/styles/atom-one-light.min.css');
    tw.core.dom.addStyleSheet('highlight-dark', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/styles/atom-one-dark.min.css');
    tw.core.dom.addScript('highlight-core', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/highlight.min.js');
    tw.events.subscribe('script.loaded', (name) => {
      if (name === 'highlight-core') {
        tw.core.dom.addScript('highlight-lang-javascript', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/javascript.min.js');
        tw.core.dom.addScript('highlight-lang-css', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/css.min.js');
        tw.core.dom.addScript('highlight-lang-xml', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/xml.min.js');
        tw.core.dom.addScript('highlight-lang-json', 'https://cdnjs.cloudflare.com/ajax/libs/highlight.js/11.10.0/languages/json.min.js');
        return;
      }
      if (name !== 'highlight-lang-json') return;
      tw.lib.highlight = window.hljs;
      // Since the scripts/css above load after the core has rendered all visible tiddlers,
      //   we have to highlight them now:
      tw.tiddlers.visible
        .forEach(title => {
          let tiddler = tw.run.getTiddler(title);
          let el = tw.run.getTiddlerElement(tiddler.title);
          el.querySelectorAll('pre code:not([data-highlighted])').forEach(el => (tw.lib.highlight?.highlightElement(el, {language: languageFromTiddlerType(tiddler.type)})));
        });
    }, 'HighlightPlugin');
    // Apply the correct light/dark highlight for the current theme on load.
    // The sheets were just added above, so themeSwitch's disableStyleSheet won't throw.
    tw.events.send('theme.switch', currentTheme());
  }, 'HighlightPlugin');

  // Re-apply on soft reload too (the highlight <link>s persist in <head>).
  tw.events.subscribe('ui.reloaded', () => tw.events.send('theme.switch', currentTheme()), 'HighlightPlugin');

  tw.events.subscribe('tiddler.rendered', ({tiddler, newElement}) => {
    newElement.querySelectorAll('pre code:not([data-highlighted])').forEach(el => (tw.lib.highlight?.highlightElement(el, {language: languageFromTiddlerType(tiddler.type)})));
  }, 'HighlightPlugin');

  function currentTheme() {
    return tw.run.getTiddlerTextRaw('$Theme').replace(/[\[\]]/g, ''); // strip [[ ]]
  }

  function languageFromTiddlerType(type) {
    switch (type) {
      case 'script/js':
        return 'javascript';
      case 'css':
        return 'css';
      case 'html/template':
        return 'xml';
      case 'json':
        return 'json';
      default:
        return '';
    }
  }
})();

/* ============================================================
   Obsidian — a modern dark theme (the new TWikki default)
   Dark, dense, muted, with a violet accent. Defines the look
   purely by assigning the shared design tokens, so every
   component (which reads the tokens) recolours automatically.
   ============================================================ */
:root {
  /* Backgrounds (layered, darkest = sidebar) */
  --colbg1: #1e1e1f; /* main pane behind notes */
  --colbg2: #262629; /* note cards, dialogs, popovers */
  --colbg3: #181819; /* sidebar, tab strip, raised chrome */
  --colbgi: #1a1a1c; /* form inputs */

  /* Foreground */
  --colfg:  #dcddde; /* body text */
  --colfgi: #e9eaec; /* input text */

  /* Neutrals & accents */
  --col0: #000000;   /* shadows */
  --col1: #9a9ba0;   /* muted text, icons */
  --col3: #7c6fd6;   /* filled controls (buttons, th) */
  --col4: #34343a;   /* hairline borders */
  --col6: #a78bfa;   /* links, hover accent */

  --notify-rgba: 124, 111, 214;

  --rad1: 6px;
  --rad2: 6px;
  --rad3: 6px;
  --rad4: 6px;

  /* Layout tokens */
  --sidebar-w: 280px;
  --accent: #a78bfa;
  --accent-2: #7c6fd6;
  --tab-bg: #181819;        /* inactive tab — matches sidebar */
  --tab-active-bg: #1e1e1f; /* active tab — matches main pane */
}
